What will the following Python OOP code output?

class Dog:
    def __init__(self, name, breed):
        self.name = name
        self.breed = breed

    def speak(self):
        return f'{self.name} says Woof!'

my_dog = Dog('Rex', 'Labrador')
print(my_dog.speak())
print(my_dog.breed)

What will this Python code output?

class Animal:
    def __init__(self, name):
        self.name = name
    def speak(self):
        return 'Some sound'

class Cat(Animal):
    def speak(self):
        return f'{self.name} says Meow'

class Duck(Animal):
    pass

c = Cat('Whiskers')
d = Duck('Donald')
print(c.speak())
print(d.speak())

